promptTranslations.en:
{
  "type": "exploded view product diagram poster",
  "subject": "VR headset",
  "style": "clean high-tech 3D render, studio lighting, glowing accents",
  "background": "{argument name=\"background color\" default=\"soft purple and blue gradient\"}",
  "header": {
    "logo": "∞ {argument name=\"product name\" default=\"Meta Quest 3\"}",
    "subtitle": "{argument name=\"main catchphrase\" default=\"A completely new reality, from a completely new structure.\"}"
  },
  "layout": {
    "centerpiece": "vertically stacked exploded view of a VR headset showing 9 distinct layers of internal components: outer shell, camera sensors, motherboard with chip, pancake lenses, internal frame, battery packs, side straps, top strap, and facial interface cushion.",
    "callout_labels": {
      "count": 8,
      "left_side": [
        "Snapdragon® XR2 Gen 2\nUnrivaled processing power for real-time experiences.",
        "Adjustable IPD mechanism\nComfortable fit for a wide range of users.",
        "Precision-engineered head strap\nErgonomics focused on comfort and stability."
      ],
      "right_side": [
        "Faceplate\nSleek design and optimal weight balance.",
        "Tracking cameras\nHigh-precision position tracking and environment recognition.",
        "Pancake lenses\nSlim design providing wide field of view and sharp visuals.",
        "High-performance battery\nOptimized power design enabling long usage.",
        "Soft facial interface\nComfortable fit for extended wear."
      ]
    },
    "footer": {
      "left_text_block": {
        "headline": "{argument name=\"bottom headline\" default=\"The experience evolves from the structure.\"}",
        "body": "Each part embodies cutting-edge technology and meticulous design supporting immersive experiences. Meta Quest 3 creates a futuristic sensation from within."
      },
      "right_logo": "∞ Meta"
    }
  }
}

promptTranslations.zh:
{
  "type": "爆炸视图产品图解海报",
  "subject": "VR头显",
  "style": "干净的高科技3D渲染，摄影棚灯光，发光装饰",
  "background": "{argument name=\"background color\" default=\"柔和的紫蓝色渐变\"}",
  "header": {
    "logo": "∞ {argument name=\"product name\" default=\"Meta Quest 3\"}",
    "subtitle": "{argument name=\"main catchphrase\" default=\"まったく新しい現実を、まったく新しい構造から。\"}"
  },
  "layout": {
    "centerpiece": "VR头显的垂直堆叠爆炸视图，展示9个不同的内部组件层：外壳、摄像头传感器、带芯片的主板、Pancake透镜、内部框架、电池组、侧带、顶带和面部接口衬垫。",
    "callout_labels": {
      "count": 8,
      "left_side": [
        "Snapdragon® XR2 Gen 2\n以卓越的处理性能实现实时体验。",
        "可调节IPD机构\n为广大用户提供舒适的贴合感。",
        "精密设计的头带\n追求舒适与稳定的人体工程学设计。"
      ],
      "right_side": [
        "前面板\n精致的设计与最佳的重量平衡。",
        "追踪摄像头\n实现高精度的位置追踪与环境感知。",
        "Pancake透镜\n轻薄设计，提供宽广视野与清晰影像。",
        "高性能电池\n支持长时间续航的优化电源设计。",
        "柔软面部接口\n实现长时间佩戴的舒适感。"
      ]
    },
    "footer": {
      "left_text_block": {
        "headline": "{argument name=\"bottom headline\" default=\"体验，源于结构的进化。\"}",
        "body": "每一个零件都蕴含着支撑沉浸式体验的尖端技术与匠心设计。Meta Quest 3从内部构建出令人感受未来的体验。"
      },
      "right_logo": "∞ Meta"
    }
  }
}

promptTranslations.pt:
{
  "type": "pôster de diagrama de produto em vista explodida",
  "subject": "headset VR",
  "style": "renderização 3D limpa e de alta tecnologia, iluminação de estúdio, detalhes brilhantes",
  "background": "{argument name=\"cor de fundo\" default=\"gradiente suave de roxo e azul\"}",
  "header": {
    "logo": "∞ {argument name=\"nome do produto\" default=\"Meta Quest 3\"}",
    "subtitle": "{argument name=\"frase principal\" default=\"Uma realidade totalmente nova, a partir de uma estrutura totalmente nova.\"}"
  },
  "layout": {
    "centerpiece": "vista explodida empilhada verticalmente de um headset VR mostrando 9 camadas distintas de componentes internos: revestimento externo, sensores de câmera, placa-mãe com chip, lentes pancake, estrutura interna, baterias, tiras laterais, tira superior e almofada de interface facial.",
    "callout_labels": {
      "count": 8,
      "left_side": [
        "Snapdragon® XR2 Gen 2\nDesempenho de processamento incrível para experiências em tempo real.",
        "Mecanismo de IPD ajustável\nAjuste confortável para uma ampla gama de usuários.",
        "Head strap de design preciso\nErgonomia focada em conforto e estabilidade."
      ],
      "right_side": [
        "Faceplate\nDesign sofisticado e equilíbrio de peso ideal.",
        "Câmeras de rastreamento\nRastreamento de posição de alta precisão e reconhecimento de ambiente.",
        "Lentes Pancake\nDesign fino que oferece amplo campo de visão e imagens nítidas.",
        "Bateria de alto desempenho\nDesign de energia otimizado para longas horas de uso.",
        "Interface facial macia\nConforto garantido mesmo após longos períodos de uso."
      ]
    },
    "footer": {
      "left_text_block": {
        "headline": "{argument name=\"manchete inferior\" default=\"A experiência evolui a partir da estrutura.\"}",
        "body": "Cada peça contém tecnologia de ponta e um design cuidadoso que sustenta a experiência imersiva. O Meta Quest 3 cria experiências que parecem vir do futuro, a partir de sua própria estrutura interna."
      },
      "right_logo": "∞ Meta"
    }
  }
}
